class Solution:
    def lastStoneWeight(self, stones: list[int]) -> int:
        import heapq
        h = [-s for s in stones]
        heapq.heapify(h)
        while len(h) > 1:
            y = -heapq.heappop(h)
            x = -heapq.heappop(h)
            if y != x:
                heapq.heappush(h, -(y - x))
        return -h[0] if h else 0

