class MedianFinder:
    def __init__(self):
        import heapq
        self.low = []   # max-heap via negatives
        self.high = []  # min-heap
        self._hq = heapq
    def addNum(self, num: int) -> None:
        self._hq.heappush(self.low, -num)
        self._hq.heappush(self.high, -self._hq.heappop(self.low))
        if len(self.high) > len(self.low):
            self._hq.heappush(self.low, -self._hq.heappop(self.high))
    def findMedian(self) -> float:
        if len(self.low) > len(self.high):
            return float(-self.low[0])
        return (-self.low[0] + self.high[0]) / 2.0

