class Solution:
    def leastInterval(self, tasks: list[str], n: int) -> int:
        from collections import Counter
        freq = sorted(Counter(tasks).values())
        maxf = freq[-1]
        idle = (maxf - 1) * n
        for f in freq[:-1][::-1]:
            if idle <= 0:
                break
            idle -= min(f, maxf - 1)
        return len(tasks) + max(0, idle)
